const express = require('express');
const multer = require('multer');
const xml2js = require('xml2js');

const app = express();
const upload = multer({ dest: './uploads/' });

app.post('/upload-config', upload.single('config'), (req, res) => {
  const configXml = req.file.buffer.toString();

  xml2js.parseString(configXml, (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send({ error: 'Failed to parse XML' });
    }

    const configSettings = {};
    for (const element of result.config[0]) {
      const key = element.$.key;
      const value = element.$.value;
      configSettings[key] = value;
    }

    // Handle external schema references
    if (result.config[0][0].$.xsiSchemaLocation) {
      // Download the schema and parse it, then validate the config against it
      // ...
    }

    res.send({ config: configSettings });
  });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});